#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        ok = all(a[i] <= a[i+1] + 1 for i in range(n-1))
        if not ok:
            a.sort()
        out_lines.append(' '.join(map(str, a)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

